import nmap
import requests
import json

class IoTScanner:
    def __init__(self, ip_address):
        self.ip_address = ip_address

    def scan_network(self):
        # Scan the network for IoT devices
        nm = nmap.PortScanner()
        nm.scan(self.ip_address, '1-65535')
        devices = nm.all_hosts()
        return devices

