import hashlib
import hmac
import secrets

class VoteSystem:
    def __init__(self):
        self.votes = {}
        self.secret_key = secrets.token_bytes(32)

    def vote(self, voter_id, candidate):
        if voter_id not in self.votes:
            self.votes[voter_id] = []
        self.votes[voter_id].append(candidate)
        return self._hash_vote(voter_id, candidate)

    def _hash_vote(self, voter_id, candidate):
        return hmac.new(self.secret_key, f"{voter_id}{candidate}".encode(), hashlib.sha256).hexdigest()

    def count_votes(self):
        votes_count = {}
        for voter_id, candidates in self.votes.items():
            for candidate in candidates:
                if candidate in votes_count:
                    votes_count[candidate] += 1
                else:
                    votes_count[candidate] = 1
        return votes_count

    def verify_vote(self, voter_id, vote_hash):
        if voter_id in self.votes:
            for candidate in self.votes[voter_id]:
                if self._hash_vote(voter_id, candidate) == vote_hash:
                    return True
        return False

